import numpy as np
from datetime import datetime
import matplotlib.pyplot as plt

# Vendor roadmap data
ROADMAPS = {
    'IBM': {
        'milestones': [
            {'year': 2023, 'qubits': 1121, 'name': 'Condor'},
            {'year': 2024, 'qubits': 1386, 'name': 'Heron system'},
            {'year': 2025, 'qubits': 4158, 'name': '3-chip Crossbill'},
            {'year': 2026, 'qubits': 10000, 'name': 'Starling'},
            {'year': 2029, 'qubits': 100000, 'name': 'Blue Jay'},
            {'year': 2033, 'qubits': 100000, 'name': 'Fault-tolerant'}
        ],
        'technology': 'superconducting'
    },
    'Google': {
        'milestones': [
            {'year': 2023, 'qubits': 105, 'name': 'Willow'},
            {'year': 2025, 'qubits': 200, 'name': 'Logical demo'},
            {'year': 2027, 'qubits': 1000, 'name': 'Logical processor'},
            {'year': 2030, 'qubits': 1000000, 'name': '1M physical'}
        ],
        'technology': 'superconducting'
    },
    'IonQ': {
        'milestones': [
            {'year': 2023, 'qubits': 32, 'name': 'Forte'},
            {'year': 2024, 'qubits': 35, 'name': 'Forte Enterprise'},
            {'year': 2025, 'qubits': 64, 'name': 'Multi-core'},
            {'year': 2028, 'qubits': 1024, 'name': 'Networked'}
        ],
        'technology': 'trapped_ion'
    },
    'Quantinuum': {
        'milestones': [
            {'year': 2023, 'qubits': 20, 'name': 'H1'},
            {'year': 2024, 'qubits': 32, 'name': 'H2'},
            {'year': 2026, 'qubits': 64, 'name': 'H3'},
            {'year': 2028, 'qubits': 100, 'name': 'Helios'}
        ],
        'technology': 'trapped_ion'
    }
}

def calculate_growth_rate(milestones: list) -> dict:
    """Calculate qubit growth rate from milestones."""
    if len(milestones) < 2:
        return {'doubling_time': None, 'cagr': None}

    years = [m['year'] for m in milestones]
    qubits = [m['qubits'] for m in milestones]

    # Calculate CAGR (Compound Annual Growth Rate)
    years_span = years[-1] - years[0]
    if years_span > 0 and qubits[0] > 0:
        cagr = (qubits[-1] / qubits[0]) ** (1/years_span) - 1
        doubling_time = np.log(2) / np.log(1 + cagr) if cagr > 0 else float('inf')
    else:
        cagr = 0
        doubling_time = float('inf')

    return {
        'doubling_time_years': round(doubling_time, 2),
        'cagr_percent': round(cagr * 100, 1),
        'start_qubits': qubits[0],
        'end_qubits': qubits[-1],
        'span_years': years_span
    }

def assess_realism(vendor: str, growth_data: dict, technology: str) -> dict:
    """Assess realism of roadmap based on historical trends."""
    # Historical doubling times by technology
    historical_doubling = {
        'superconducting': 1.5,  # ~18 months historically
        'trapped_ion': 2.5,     # Slower scaling
        'neutral_atom': 1.0     # Fastest recent scaling
    }

    expected_doubling = historical_doubling.get(technology, 2.0)
    claimed_doubling = growth_data['doubling_time_years']

    if claimed_doubling < expected_doubling * 0.7:
        assessment = 'Aggressive'
        confidence = 'Low'
    elif claimed_doubling < expected_doubling * 1.3:
        assessment = 'Reasonable'
        confidence = 'Medium'
    else:
        assessment = 'Conservative'
        confidence = 'High'

    return {
        'assessment': assessment,
        'confidence': confidence,
        'claimed_doubling': claimed_doubling,
        'historical_doubling': expected_doubling,
        'ratio': round(claimed_doubling / expected_doubling, 2)
    }

def analyze_roadmap_consistency(roadmaps: dict) -> dict:
    """
    Analyze and compare vendor roadmaps.
    """
    growth_rates = {}
    realism_assessments = {}
    milestone_timeline = {}

    for vendor, data in roadmaps.items():
        # Calculate growth rates
        growth = calculate_growth_rate(data['milestones'])
        growth_rates[vendor] = growth

        # Assess realism
        realism = assess_realism(vendor, growth, data['technology'])
        realism_assessments[vendor] = realism

        # Build timeline
        for m in data['milestones']:
            year = m['year']
            if year not in milestone_timeline:
                milestone_timeline[year] = []
            milestone_timeline[year].append({
                'vendor': vendor,
                'qubits': m['qubits'],
                'name': m['name']
            })

    # Find consensus milestones
    consensus_view = {
        2025: 'Early logical qubit demonstrations',
        2027: '10-50 logical qubits',
        2030: '100+ logical qubits, first applications',
        2035: 'Cryptographically-relevant quantum computing'
    }

    return {
        'growth_rates': growth_rates,
        'realism_assessments': realism_assessments,
        'milestone_timeline': dict(sorted(milestone_timeline.items())),
        'consensus_view': consensus_view
    }

def plot_roadmap_comparison(roadmaps: dict):
    """Visualize roadmap comparisons."""
    plt.figure(figsize=(14, 8))

    colors = {'IBM': 'blue', 'Google': 'red', 'IonQ': 'green', 'Quantinuum': 'purple'}

    for vendor, data in roadmaps.items():
        years = [m['year'] for m in data['milestones']]
        qubits = [m['qubits'] for m in data['milestones']]

        plt.semilogy(years, qubits, 'o-', color=colors.get(vendor, 'gray'),
                    linewidth=2, markersize=8, label=vendor)

        # Annotate key milestones
        for m in data['milestones']:
            if m['qubits'] >= 1000:
                plt.annotate(m['name'], (m['year'], m['qubits']),
                           textcoords="offset points", xytext=(0,10),
                           fontsize=8, ha='center')

    # Add milestone regions
    plt.axhspan(1, 100, alpha=0.1, color='yellow', label='NISQ Era')
    plt.axhspan(100, 10000, alpha=0.1, color='orange', label='Early FT')
    plt.axhspan(10000, 10000000, alpha=0.1, color='green', label='Full FT')

    plt.xlabel('Year', fontsize=12)
    plt.ylabel('Physical Qubits (log scale)', fontsize=12)
    plt.title('Quantum Computing Roadmap Comparison', fontsize=14)
    plt.legend(loc='upper left')
    plt.grid(True, alpha=0.3)
    plt.xlim(2022, 2035)

    plt.tight_layout()
    plt.show()

# Run analysis
result = analyze_roadmap_consistency(ROADMAPS)

print("QUANTUM COMPUTING ROADMAP ANALYSIS")
print("="*70)

print("\nGrowth Rates by Vendor:")
print("-"*70)
for vendor, data in result['growth_rates'].items():
    print(f"\n{vendor}:")
    print(f"  Doubling time: {data['doubling_time_years']} years")
    print(f"  CAGR: {data['cagr_percent']}%")
    print(f"  Scaling: {data['start_qubits']} -> {data['end_qubits']} qubits")

print("\n" + "="*70)
print("Realism Assessment:")
print("-"*70)
for vendor, data in result['realism_assessments'].items():
    print(f"  {vendor:15s}: {data['assessment']:12s} (Confidence: {data['confidence']})")

print("\n" + "="*70)
print("Industry Consensus View:")
print("-"*70)
for year, milestone in result['consensus_view'].items():
    print(f"  {year}: {milestone}")

