            {'year': 2023, 'milestone': 'Forte system', 'announced_date': 2022},
            {'year': 2025, 'milestone': '64 qubits networked', 'announced_date': 2023}
        ],
        'achieved': [
            {'year': 2022, 'milestone': '32 qubits (delayed)', 'met': False, 'delta': 1},
            {'year': 2023, 'milestone': 'Forte (32 qubits)', 'met': True, 'delta': 0}
        ]
    }
}

def track_milestone_delivery(vendor: str, announced: list, achieved: list) -> dict:
    """
    Track vendor milestone delivery performance.
    """
    total_announced = len(announced)

    # Match announcements to achievements
    delivered = []
    pending = []
    missed = []
    current_year = 2024

    for ann in announced:
        target_year = ann['year']

        # Find matching achievement
        matching = [a for a in achieved if a['year'] <= target_year + 1]

        if target_year <= current_year:
            # Should have been delivered
            found = False
            for ach in achieved:
                if ach['year'] == target_year or (ach['year'] == target_year + 1):
                    delivered.append({
                        'announced': ann,
                        'achieved': ach,
                        'on_time': ach.get('met', True)
                    })
                    found = True
                    break
            if not found:
                missed.append(ann)
        else:
            pending.append(ann)

    # Calculate credibility score
    if total_announced == 0:
        credibility = 50
    else:
        delivered_count = len(delivered)
        on_time_count = sum(1 for d in delivered if d['on_time'])

        delivery_rate = delivered_count / max(1, delivered_count + len(missed))
        on_time_rate = on_time_count / max(1, delivered_count)

        credibility = (delivery_rate * 50 + on_time_rate * 50)

    # Grade based on credibility
    if credibility >= 90:
        grade = 'A'
    elif credibility >= 75:
        grade = 'B'
    elif credibility >= 60:
        grade = 'C'
    else:
        grade = 'D'

    return {
        'vendor': vendor,
        'total_announced': total_announced,
        'delivered': len(delivered),
        'pending': len(pending),
        'missed': len(missed),
        'credibility_score': round(credibility, 1),
        'grade': grade,
        'delivered_details': delivered,
        'pending_milestones': pending,
        'missed_milestones': missed
    }

def generate_credibility_report(vendor_history: dict) -> dict:
    """Generate credibility report for all vendors."""
    reports = {}

    for vendor, data in vendor_history.items():
        reports[vendor] = track_milestone_delivery(
            vendor, 
            data['announced'], 
            data['achieved']
        )

    # Rank by credibility
    ranked = sorted(reports.items(), key=lambda x: -x[1]['credibility_score'])

    return {
        'individual_reports': reports,
        'ranking': [(v, r['credibility_score'], r['grade']) for v, r in ranked],
        'most_reliable': ranked[0][0] if ranked else None
    }

# Generate report
print("QUANTUM COMPUTING MILESTONE TRACKER")
print("="*70)

report = generate_credibility_report(VENDOR_HISTORY)

print("\nCredibility Rankings:")
print("-"*50)
print(f"{'Vendor':<15} | {'Score':>8} | {'Grade':>6}")
print("-"*50)
for vendor, score, grade in report['ranking']:
    print(f"{vendor:<15} | {score:>8.1f} | {grade:>6}")

print("\n" + "="*70)
print("Detailed Vendor Reports:")
print("="*70)

for vendor, data in report['individual_reports'].items():
    print(f"\n{vendor}:")
    print(f"  Announced: {data['total_announced']}, Delivered: {data['delivered']}, "
          f"Pending: {data['pending']}, Missed: {data['missed']}")
    print(f"  Credibility: {data['credibility_score']}/100 (Grade: {data['grade']})")

    if data['pending_milestones']:
        print(f"  Upcoming:")
        for p in data['pending_milestones']:
            print(f"    - {p['year']}: {p['milestone']}")
